+			found := false
+			for _, arg := range info.Args {
+				if arg == tt.wantArg || (tt.preset == AgentGemini && arg == "yolo") {
+					found = true
+					break
+				}
+			}
+			if !found {
+				t.Errorf("preset %s args %v missing expected %s", tt.preset, info.Args, tt.wantArg)
+			}
+		})
